// PromiseLexerInit initializes any static state used to implement PromiseLexer. By default the
// static state used to implement the lexer is lazily initialized during the first call to
// NewPromiseLexer(). You can call this function if you wish to initialize the static state ahead
// of time.
func PromiseLexerInit() {
	staticData := &PromiseLexerLexerStaticData
	staticData.once.Do(promiselexerLexerInit)
}

// NewPromiseLexer produces a new lexer instance for the optional input antlr.CharStream.
func NewPromiseLexer(input antlr.CharStream) *PromiseLexer {
	PromiseLexerInit()
	l := new(PromiseLexer)
	l.BaseLexer = antlr.NewBaseLexer(input)
	staticData := &PromiseLexerLexerStaticData
	l.Interpreter = antlr.NewLexerATNSimulator(l, staticData.atn, staticData.decisionToDFA, staticData.PredictionContextCache)
	l.channelNames = staticData.ChannelNames
	l.modeNames = staticData.ModeNames
	l.RuleNames = staticData.RuleNames
	l.LiteralNames = staticData.LiteralNames
	l.SymbolicNames = staticData.SymbolicNames
	l.GrammarFileName = "PromiseLexer.g4"
	// TODO: l.EOF = antlr.TokenEOF

	return l
}

